import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';

const BookingHistory = () => {
  const [bookings, setBookings] = useState([]);
  const [filter, setFilter] = useState('all');
  const navigate = useNavigate();

  useEffect(() => {
    loadBookings();
  }, []);

  const loadBookings = () => {
    // Mock booking data
    const mockBookings = [
      {
        id: 'BK123456',
        busName: 'Express Travels',
        busType: 'AC Sleeper',
        route: 'New York → Los Angeles',
        date: '2024-04-15',
        departure: '08:00 AM',
        arrival: '02:00 PM',
        seats: ['12', '13'],
        totalAmount: 900,
        status: 'Confirmed',
        bookingDate: '2024-04-01',
        amenities: ['WiFi', 'Charging Port', 'Blanket', 'Water Bottle']
      },
      {
        id: 'BK789012',
        busName: 'Royal Bus Service',
        busType: 'Non AC Seater',
        route: 'Chicago → Houston',
        date: '2024-03-20',
        departure: '10:30 AM',
        arrival: '05:30 PM',
        seats: ['5'],
        totalAmount: 280,
        status: 'Completed',
        bookingDate: '2024-03-15',
        amenities: ['WiFi', 'Charging Port']
      },
      {
        id: 'BK345678',
        busName: 'Super Deluxe',
        busType: 'AC Seater',
        route: 'Philadelphia → Phoenix',
        date: '2024-02-10',
        departure: '02:00 PM',
        arrival: '09:00 PM',
        seats: ['8', '9', '10'],
        totalAmount: 1050,
        status: 'Cancelled',
        bookingDate: '2024-02-05',
        amenities: ['WiFi', 'Charging Port', 'Snacks', 'Entertainment']
      }
    ];
    setBookings(mockBookings);
  };

  const filteredBookings = bookings.filter(booking => {
    if (filter === 'all') return true;
    return booking.status.toLowerCase() === filter;
  });

  const handleTrackBus = (booking) => {
    navigate('/track-bus', { state: { booking } });
  };

  const handleDownloadTicket = (booking) => {
    alert(`Downloading ticket for booking ${booking.id}`);
  };

  const handleCancelBooking = (bookingId) => {
    if (window.confirm('Are you sure you want to cancel this booking?')) {
      setBookings(bookings.map(b => 
        b.id === bookingId ? { ...b, status: 'Cancelled' } : b
      ));
      alert('Booking cancelled successfully');
    }
  };

  const handleBookAgain = (booking) => {
    navigate('/search', { 
      state: { 
        source: booking.route.split(' → ')[0],
        destination: booking.route.split(' → ')[1]
      }
    });
  };

  const getStatusColor = (status) => {
    switch (status) {
      case 'Confirmed': return '#28a745';
      case 'Completed': return '#6c757d';
      case 'Cancelled': return '#dc3545';
      default: return '#ffc107';
    }
  };

  return (
    <div className="container">
      <div className="card">
        <h2>Booking History</h2>

        <div style={{ display: 'flex', gap: '10px', marginBottom: '20px' }}>
          <button
            className={filter === 'all' ? 'btn' : 'btn btn-secondary'}
            onClick={() => setFilter('all')}
            style={{ padding: '5px 15px' }}
          >
            All ({bookings.length})
          </button>
          <button
            className={filter === 'confirmed' ? 'btn' : 'btn btn-secondary'}
            onClick={() => setFilter('confirmed')}
            style={{ padding: '5px 15px' }}
          >
            Confirmed ({bookings.filter(b => b.status === 'Confirmed').length})
          </button>
          <button
            className={filter === 'completed' ? 'btn' : 'btn btn-secondary'}
            onClick={() => setFilter('completed')}
            style={{ padding: '5px 15px' }}
          >
            Completed ({bookings.filter(b => b.status === 'Completed').length})
          </button>
          <button
            className={filter === 'cancelled' ? 'btn' : 'btn btn-secondary'}
            onClick={() => setFilter('cancelled')}
            style={{ padding: '5px 15px' }}
          >
            Cancelled ({bookings.filter(b => b.status === 'Cancelled').length})
          </button>
        </div>

        {filteredBookings.length === 0 ? (
          <p>No bookings found for the selected filter.</p>
        ) : (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
            {filteredBookings.map(booking => (
              <div key={booking.id} className="card" style={{ border: '1px solid #ddd' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '15px' }}>
                  <div>
                    <h3 style={{ margin: '0 0 5px 0' }}>{booking.busName}</h3>
                    <p style={{ margin: '0', color: '#666', fontSize: '14px' }}>{booking.busType}</p>
                    <div style={{ 
                      padding: '4px 8px', 
                      borderRadius: '4px', 
                      backgroundColor: getStatusColor(booking.status),
                      color: 'white',
                      fontSize: '12px',
                      fontWeight: 'bold',
                      display: 'inline-block',
                      marginTop: '5px'
                    }}>
                      {booking.status}
                    </div>
                  </div>
                  <div style={{ textAlign: 'right' }}>
                    <div style={{ fontSize: '18px', fontWeight: 'bold', color: '#007bff' }}>
                      ₹{booking.totalAmount}
                    </div>
                    <div style={{ fontSize: '12px', color: '#666' }}>
                      Booking ID: {booking.id}
                    </div>
                  </div>
                </div>

                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px', marginBottom: '15px' }}>
                  <div>
                    <h4 style={{ fontSize: '14px', marginBottom: '5px' }}>Journey Details</h4>
                    <p style={{ margin: '2px 0', fontSize: '13px' }}><strong>Route:</strong> {booking.route}</p>
                    <p style={{ margin: '2px 0', fontSize: '13px' }}><strong>Date:</strong> {booking.date}</p>
                    <p style={{ margin: '2px 0', fontSize: '13px' }}><strong>Time:</strong> {booking.departure} - {booking.arrival}</p>
                    <p style={{ margin: '2px 0', fontSize: '13px' }}><strong>Seats:</strong> {booking.seats.join(', ')}</p>
                  </div>
                  <div>
                    <h4 style={{ fontSize: '14px', marginBottom: '5px' }}>Booking Info</h4>
                    <p style={{ margin: '2px 0', fontSize: '13px' }}><strong>Booked on:</strong> {booking.bookingDate}</p>
                    <p style={{ margin: '2px 0', fontSize: '13px' }}><strong>Amenities:</strong> {booking.amenities.join(', ')}</p>
                  </div>
                </div>

                <div style={{ display: 'flex', gap: '10px', justifyContent: 'flex-end' }}>
                  {booking.status === 'Confirmed' && (
                    <>
                      <button
                        className="btn btn-secondary"
                        onClick={() => handleTrackBus(booking)}
                        style={{ padding: '5px 15px', fontSize: '12px' }}
                      >
                        Track Bus
                      </button>
                      <button
                        className="btn btn-secondary"
                        onClick={() => handleDownloadTicket(booking)}
                        style={{ padding: '5px 15px', fontSize: '12px' }}
                      >
                        Download Ticket
                      </button>
                      <button
                        className="btn"
                        onClick={() => handleCancelBooking(booking.id)}
                        style={{ 
                          padding: '5px 15px', 
                          fontSize: '12px',
                          backgroundColor: '#dc3545'
                        }}
                      >
                        Cancel
                      </button>
                    </>
                  )}
                  {booking.status === 'Completed' && (
                    <>
                      <button
                        className="btn btn-secondary"
                        onClick={() => handleDownloadTicket(booking)}
                        style={{ padding: '5px 15px', fontSize: '12px' }}
                      >
                        Download Ticket
                      </button>
                      <button
                        className="btn"
                        onClick={() => handleBookAgain(booking)}
                        style={{ padding: '5px 15px', fontSize: '12px' }}
                      >
                        Book Again
                      </button>
                    </>
                  )}
                  {booking.status === 'Cancelled' && (
                    <button
                      className="btn"
                      onClick={() => handleBookAgain(booking)}
                      style={{ padding: '5px 15px', fontSize: '12px' }}
                    >
                      Book Again
                    </button>
                  )}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default BookingHistory;
